class Solution:
    def lastRemaining(self, n: int) -> int:
        def f(n, left):
            if n == 1: return 1
            half = f(n // 2, not left)
            if n % 2 == 0:
                return half if left else 2 * half
            return half if left else 2 * half + 1
        return f(n, True)

