class Solution {
    int f(int n, bool left) {
        if (n == 1) return 1;
        int half = f(n/2, !left);
        if (n % 2 == 0) return left ? half : 2*half;
        return left ? half : 2*half + 1;
    }
public:
    int lastRemaining(int n) { return f(n, true); }
};

